import{c as r,Q as t,j as i,m as a}from"./chunks/framework.rlpw0eGz.js";const u=JSON.parse('{"title":"🔌 Driver Management Guide","description":"","frontmatter":{},"headers":[],"relativePath":"DRIVERS.md","filePath":"DRIVERS.md"}'),o={name:"DRIVERS.md"};function s(n,e,l,d,c,p){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="🔌-driver-management-guide" tabindex="-1">🔌 Driver Management Guide <a class="header-anchor" href="#🔌-driver-management-guide" aria-label="Permalink to &quot;🔌 Driver Management Guide&quot;">​</a></h1><p>Device drivers are the translation layer between your operating system and physical hardware components. Installing correct, optimized drivers is critical to achieve high stability, prevent Blue Screen of Death (BSOD) crashes, and unlock maximum graphics performance.</p><hr><h2 id="🎯-post-installation-driver-update-priorities" tabindex="-1">🎯 Post-Installation Driver Update Priorities <a class="header-anchor" href="#🎯-post-installation-driver-update-priorities" aria-label="Permalink to &quot;🎯 Post-Installation Driver Update Priorities&quot;">​</a></h2><p>After a clean Windows installation (e.g., using our <code>autounattend.xml</code>), update your drivers in this exact sequence to ensure system stability:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[1. Motherboard Chipset] ──&gt; [2. Graphics Card (GPU)] ──&gt; [3. Network (LAN/WiFi)] ──&gt; [4. NVMe/SATA Storage] ──&gt; [5. Sound/Audio]</span></span></code></pre></div><h3 id="_1-motherboard-chipset-drivers-priority-1-critical" tabindex="-1">1. Motherboard Chipset Drivers (Priority 1 - Critical) <a class="header-anchor" href="#_1-motherboard-chipset-drivers-priority-1-critical" aria-label="Permalink to &quot;1. Motherboard Chipset Drivers (Priority 1 - Critical)&quot;">​</a></h3><ul><li><em>Why</em>: Governs bus communications between the CPU, RAM, and PCI Express slots.</li><li><em>Downloads Needed</em>: Intel Chipset Device Software / Management Engine (ME) or AMD Ryzen Chipset Drivers.</li><li><em>Impact</em>: Stabilizes CPU voltages, unlocks correct power scheduling, and ensures USB ports operate at full speeds.</li></ul><h3 id="_2-graphics-card-drivers-priority-1-critical" tabindex="-1">2. Graphics Card Drivers (Priority 1 - Critical) <a class="header-anchor" href="#_2-graphics-card-drivers-priority-1-critical" aria-label="Permalink to &quot;2. Graphics Card Drivers (Priority 1 - Critical)&quot;">​</a></h3><ul><li><em>Why</em>: Crucial for gaming, 3D rendering, and hardware video acceleration.</li><li><em>Downloads Needed</em>: <ul><li><strong>NVIDIA GeForce</strong>: Geforce Game Ready Drivers (from nvidia.com).</li><li><strong>AMD Radeon</strong>: Software Adrenalin Edition (from amd.com).</li><li><strong>Intel Arc</strong>: Arc Graphics Drivers (from intel.com).</li></ul></li><li><em>Impact</em>: Restores high-resolution output, enables custom display refresh rates, and updates API support (DirectX 12, Vulkan).</li></ul><h3 id="_3-network-adapters-priority-1-critical" tabindex="-1">3. Network Adapters (Priority 1 - Critical) <a class="header-anchor" href="#_3-network-adapters-priority-1-critical" aria-label="Permalink to &quot;3. Network Adapters (Priority 1 - Critical)&quot;">​</a></h3><ul><li><em>Why</em>: Stabilizes ping, resolves packet loss, and increases download speeds.</li><li><em>Downloads Needed</em>: Realtek LAN/WiFi, Intel Ethernet (e.g., I225-V/I226-V), or Killer Network drivers.</li></ul><h3 id="_4-storage-controllers-priority-2-important" tabindex="-1">4. Storage Controllers (Priority 2 - Important) <a class="header-anchor" href="#_4-storage-controllers-priority-2-important" aria-label="Permalink to &quot;4. Storage Controllers (Priority 2 - Important)&quot;">​</a></h3><ul><li><em>Why</em>: Improves file access speeds and NVMe temperatures.</li><li><em>Downloads Needed</em>: Standard NVMe storage controller drivers (e.g., Samsung NVMe Driver).</li></ul><h3 id="_5-sound-audio-priority-2-important" tabindex="-1">5. Sound &amp; Audio (Priority 2 - Important) <a class="header-anchor" href="#_5-sound-audio-priority-2-important" aria-label="Permalink to &quot;5. Sound &amp; Audio (Priority 2 - Important)&quot;">​</a></h3><ul><li><em>Why</em>: Enables high-fidelity audio output and mic inputs.</li><li><em>Downloads Needed</em>: Realtek High Definition Audio Drivers.</li></ul><hr><h2 id="🛠️-integrated-driver-utilities" tabindex="-1">🛠️ Integrated Driver Utilities <a class="header-anchor" href="#🛠️-integrated-driver-utilities" aria-label="Permalink to &quot;🛠️ Integrated Driver Utilities&quot;">​</a></h2><p>The <code>Drivers/</code> directory contains tools to assist with automatic scanning, identification, and update processes:</p><h3 id="_1-driver-booster" tabindex="-1">1. Driver Booster <a class="header-anchor" href="#_1-driver-booster" aria-label="Permalink to &quot;1. Driver Booster&quot;">​</a></h3><ul><li><strong>File</strong>: <code>Driver Booster.exe</code> (by IObit)</li><li><strong>How it Works</strong>: Scans your hardware IDs against a massive cloud database of WHQL-certified drivers.</li><li><strong>Best For</strong>: Speed. Allows one-click detection and automatic background installation of all missing motherboard, USB, and legacy drivers.</li></ul><h3 id="_2-3dp-chip" tabindex="-1">2. 3DP Chip <a class="header-anchor" href="#_2-3dp-chip" aria-label="Permalink to &quot;2. 3DP Chip&quot;">​</a></h3><ul><li><strong>File</strong>: <code>3DP Chip.exe</code></li><li><strong>How it Works</strong>: A lightweight, portable diagnostic tool that instantly detects your specific motherboard, CPU, GPU, Network Card, and Sound Card.</li><li><strong>Best For</strong>: post-install setups. It provides direct, clean links to official, stripped-down hardware drivers without bundling bloated software.</li></ul><h3 id="_3-driver-identifier" tabindex="-1">3. Driver Identifier <a class="header-anchor" href="#_3-driver-identifier" aria-label="Permalink to &quot;3. Driver Identifier&quot;">​</a></h3><ul><li><strong>File</strong>: <code>driveridentifier_setup.exe</code></li><li><strong>How it Works</strong>: Scans the system, generates a local HTML report of all hardware components with their corresponding VEN (Vendor) and DEV (Device) strings, and links to verified driver packages.</li><li><strong>Best For</strong>: Finding extremely rare or legacy drivers for &quot;Unknown Devices&quot; in Device Manager.</li></ul><hr><h2 id="🔒-safe-update-practices" tabindex="-1">🔒 Safe Update Practices <a class="header-anchor" href="#🔒-safe-update-practices" aria-label="Permalink to &quot;🔒 Safe Update Practices&quot;">​</a></h2><p>Applying driver updates can sometimes cause system stability regressions. Follow these safety protocols:</p><h3 id="step-1-create-a-system-restore-point-mandatory" tabindex="-1">Step 1: Create a System Restore Point (Mandatory) <a class="header-anchor" href="#step-1-create-a-system-restore-point-mandatory" aria-label="Permalink to &quot;Step 1: Create a System Restore Point (Mandatory)&quot;">​</a></h3><p>Before altering any drivers, establish a system-wide fallback:</p><ol><li>Open the Start menu, search for <strong>Create a restore point</strong>, and select it.</li><li>Under System Protection, select your primary System Drive (typically <code>C:</code>) and click <strong>Configure</strong>. Ensure system protection is <strong>Turned On</strong> and allocate at least 2% disk space.</li><li>Click <strong>Create...</strong>, name it <code>Pre-Driver Update</code>, and click OK.</li></ol><h3 id="step-2-clean-install-graphics-drivers-using-ddu" tabindex="-1">Step 2: Clean Install Graphics Drivers using DDU <a class="header-anchor" href="#step-2-clean-install-graphics-drivers-using-ddu" aria-label="Permalink to &quot;Step 2: Clean Install Graphics Drivers using DDU&quot;">​</a></h3><p>When upgrading graphics cards or resolving display stutters, performing a standard over-the-top installer update can leave corrupted cache residues. Perform a clean install instead:</p><ol><li>Download <strong>Display Driver Uninstaller (DDU)</strong> (an external open-source utility).</li><li>Download your latest NVIDIA/AMD driver installer.</li><li><strong>Disconnect from the Internet</strong>: This is crucial to prevent Windows Update from automatically downloading generic display drivers.</li><li>Reboot Windows into <strong>Safe Mode</strong>: <ul><li>Hold <code>Shift</code> while clicking <strong>Restart</strong> in the Start Menu.</li><li>Navigate to <strong>Troubleshoot &gt; Advanced Options &gt; Startup Settings &gt; Restart</strong>.</li><li>Press <code>4</code> or <code>F4</code> to enable Safe Mode.</li></ul></li><li>Open DDU, select your Device Type (<strong>GPU</strong>), select your vendor (<strong>NVIDIA</strong> or <strong>AMD</strong>), and click <strong>Clean and restart</strong>.</li><li>Once Windows boots back to the desktop, run your downloaded graphics installer, select &quot;Custom/Advanced Installation&quot;, and check &quot;Perform a Clean Installation&quot; if available.</li><li>Reconnect the internet.</li></ol><hr><h2 id="🔍-post-installation-verification" tabindex="-1">🔍 Post-Installation Verification <a class="header-anchor" href="#🔍-post-installation-verification" aria-label="Permalink to &quot;🔍 Post-Installation Verification&quot;">​</a></h2><p>Confirm your drivers are working correctly:</p><ol><li><strong>Check Device Manager</strong>: <ul><li>Press <code>Win + X</code> and select <strong>Device Manager</strong>.</li><li>Ensure there are <strong>no yellow exclamation marks</strong> or categories labeled &quot;Unknown Device&quot;.</li><li>If you see &quot;Microsoft Basic Display Adapter&quot;, your graphics drivers are not active.</li></ul></li><li><strong>Verify High Refresh Rate</strong>: <ul><li>Navigate to <strong>Settings &gt; System &gt; Display &gt; Advanced Display</strong>.</li><li>Confirm your monitor is set to its maximum supported refresh rate (e.g., 144Hz, 240Hz) rather than the default 60Hz.</li></ul></li></ol>',38)])])}const g=r(o,[["render",s]]);export{u as __pageData,g as default};
